var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"윽……?!","JPN":"うっ……！？","ENG":"Ngh...?!","TWN":"呃……？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"부학회장을 데려왔소, 학회장.","JPN":"副学会長を連れてきた、学会長。","ENG":"President, I've brought Vice President.","TWN":"我把副學會長帶來了，學會長。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"수고하셨어요, 하이드리히 소장님. 학부장답게 일처리가 깔끔하시네요.","JPN":"ご苦労様です、ハイドリヒ所長。学部長らしい無駄のない仕事ぶりですね。","ENG":"Thank you, Chief Heydrich. As a dean, your work is always spotless.","TWN":"辛苦你了，海德里希所長。不愧是學院院長，辦事就是效率。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"귀빈께서 도착하셨군요. 그렇다면 예정대로 의식을 진행하도록 하죠.","JPN":"貴賓が到着されましたか。それでは予定どおり儀式を行いましょう。","ENG":"The VIP has arrived. Then the ritual shall proceed as planned.","TWN":"貴賓到了呢。那就按照計畫進行儀式吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 모쪼록 잘 부탁드려요.","JPN":"はい。どうかよろしくお願いしますね。","ENG":"Yes. Please do.","TWN":"好，那就拜託了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"관악기가 없는 악단의 연주는 기운 잃은 푸념으로 들리기 쉽죠.","JPN":"管楽器のいない楽団の演奏は、勢いのない愚痴に聞こえやすいもの。","ENG":"An orchestra without a trumpet sounds like nails on a chalkboard.","TWN":"沒有管樂器的樂團演奏很容易被聽成有氣無力的呻吟。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"루나, 당신이 자리를 비우는 바람에 연주가 상당히 지연되었어요.","JPN":"ルナ、あなたが留守にしていたせいで演奏がかなり遅れました。","ENG":"Luna, your tardiness has significantly delayed our performance.","TWN":"露娜，因為你不在，演奏推遲了很久。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지, 지지, 지휘자님…… 저는, 그게 어디까지나…….","JPN":"ま、まま、マエストロ……アタシは、その、あくまで……","ENG":"C-chief Conductor... I was... just...","TWN":"指…指指、…揮家……我，那個……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"부학회장님을 감시한 일이라면 셰나에게 전해 들었습니다.","JPN":"副学会長を監視していたことでしたら、シェナから聞いています。","ENG":"Shena informed me that you were tasked with monitoring the Vice President.","TWN":"監視副學會長的事，我已經聽世娜說了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그러니 이제 본연의 의무로 돌아갈 시간이에요.","JPN":"ですので、もう本来の義務に戻る時間です。","ENG":"However, it is now time you returned to your duties.","TWN":"所以，現在是時候回歸本職工作了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이번 연주는…… 평소와는 조금 다른 것 같던데…….","JPN":"今回の演奏は……いつもと少し違うようでしたが……","ENG":"The music... It sounds a little different than usual...","TWN":"這次演奏……和平時好像有點不太一樣……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"의외로군요. 당신이 제 지휘에 의문을 가지시는 건가요?","JPN":"意外ですね。あなたが私の指揮に疑問を持つのですか？","ENG":"How odd. Are you questioning my conducting skills, Luna?","TWN":"真意外啊。你是在懷疑我的指揮嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아, 아뇨! 그건 아니지만요!","JPN":"い、いいえ！　そんなことありません！","ENG":"N-no! Not at all, but...!","TWN":"沒…沒有！不是那樣的！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그래요. 연주 중에는 순종적인 악기가 되도록 노력하세요.","JPN":"そうですか。演奏中は従順な楽器になれるよう、努力しなさい。","ENG":"Good. Now please try to be an obedient instrument while we perform.","TWN":"是的，演奏期間儘量成為順從的樂器吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"좋은 음색을 내지 않는 악기는 간수할 가치도 없으니 말입니다.","JPN":"いい音色を出せない楽器はしまっておく価値もありませんので。","ENG":"For an instrument with a bad tone is not worth keeping.","TWN":"因為發不出好音色的樂器，根本不值得收藏。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"……그, 네.","JPN":"……その、はい。","ENG":"...Y-yes, ma'am...","TWN":"……啊，是的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"반가워요, 레지나 님. 제가 없는 동안 아주 먹음직스러운 친구 분들을 사귀셨네요.","JPN":"またお会いできて嬉しいです、レジーナ様。我々がいない間に、とても美味しそうな友達ができましたね。","ENG":"Hello, Miss Regina. It seems what you made some appetizing friends while we were away.","TWN":"很高興見到你，蕾佳娜。我們不在的這段時間，你交到了看起來很好吃的朋友呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마이트너……","JPN":"マイトナー……","ENG":"Meitner...","TWN":"邁特納……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 오랜만이에요. 아니, 이 세계에서는 처음이던가요?","JPN":"はい。お久しぶりです。あ、この世界では初めましてでしたか？","ENG":"Yes, it's good to see you again. Oh, wait. Isn't this our first meeting in this world?","TWN":"是，好久不見，啊不，在這個世界是第一次見面嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"다리가 부러졌네? 에스코트해 준 아저씨가 좀 거칠게 다뤘나 봐.","JPN":"足が折れてるね？　エスコートしてくれたおじさんに乱暴に扱われたのかな。","ENG":"Hey, your leg is broken. Was Heydrich a little rough with you while he escorted you here?","TWN":"你的腿斷了啊？給你帶路的大叔，看來有點粗魯啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"괜찮아요, 리벳. 곧 부상 같은 것 때문에 고통스러워하지 않게 되실 테니까요.","JPN":"大丈夫ですよ、リベット。もうすぐ怪我なんかで苦しむこともなくなるでしょうから。","ENG":"It's no problem, Rivet. Soon she will never have to feel pain again.","TWN":"沒關係，里維。因為她很快就不會再因為受傷而痛苦了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델, 게다가 리벳까지……","JPN":"エデル、それにリベットまで……","ENG":"Edel... And even you, Rivet...","TWN":"艾瑟兒，還有里維……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"대체 왜 이런 짓을 벌이는 거죠?","JPN":"いったいどうしてこのようなことをするのですか？","ENG":"Why are you doing this?","TWN":"你們究竟為什麼要做這種事？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"기관과 전면전을 벌이는 것도, 합중국을 도발하는 것도……","JPN":"機関と全面戦争を始めたのも、合衆国を挑発したことも……","ENG":"Waging an all-out war against the Institution, as well as provoking the States...","TWN":"和機關全面開戰，還有挑釁合眾國……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"허기를 해결할 방법은 그것 말고도 많잖아요. 세상을 전부 적으로 돌리고 싶어진 거예요?","JPN":"空腹を満たす方法はそれ以外にもいくらでもあるはずです。全世界を敵に回したくなったのですか？","ENG":"There are other means to satisfy your hunger. Or do you want to turn the world against you?","TWN":"解決饑餓的辦法，除了這個還有很多不是嘛。你們是想與全世界為敵嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아직 늦지 않았어요. 아니, 늦었을지 몰라도, 지금이라면 돌이킬 수 있어요.","JPN":"まだ遅くありません。いいえ、遅いかもしれませんが、今なら取り戻せますわ。","ENG":"It is still not too late. No, perhaps it is. But you can still put an end to it.","TWN":"還不算太遲，啊不，或許已經遲了，但現在還可以挽回。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"괴물이 되고 싶은 거예요? 당신도 그렇게 되길 원하진 않잖아요!","JPN":"化け物になりたいのですか？　あなたもそうなることを望んではいないでしょう！","ENG":"Do you want to become a monster? I know that is not what you want!","TWN":"你想成為怪物嗎？你也不希望那樣不是嘛！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"……오해하지 마세요, 레지나 님. 이번 일은 저희들의 굶주림 때문이 아니에요.","JPN":"……誤解しないでください、レジーナ様。今回のことは我々の空腹を満たすためではありません。","ENG":"...Miss Regina, don't be mistaken. We are not doing this out of hunger.","TWN":"……別誤會，蕾佳娜。這次的事不是因為我們的饑餓。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 왜……!","JPN":"それなら、どうして……！","ENG":"Then why...?!","TWN":"那是為什麼……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님과 함께하기 위해서죠.","JPN":"レジーナ様とご一緒するためです。","ENG":"It's to be with you.","TWN":"是為了和蕾佳娜在一起。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희도 처음에는 조금 더 온건한 방식을 시도해 봤어요.","JPN":"我々も最初はもう少し穏やかな方法を試しました。","ENG":"In the beginning, we have attempted safer means.","TWN":"我們一開始也嘗試了更穩妥的方式。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"처음에는 주민들의 현실 개변력을 활용해서 해결할 수 있으리라고 예상했죠.","JPN":"最初は住民の現実改変力を活用して解決できると予想していました。","ENG":"We believed that using the residents' CRF would work.","TWN":"最初我們以為可以利用居民們的制裁力來解決。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하지만 결과는 좋지 않았어요. 기꺼이 희생해 주신 분들께는 애석할 따름이랍니다.","JPN":"ですが、結果はあまりかんばしくなかった。喜んで犠牲になってくれた方々には残念です。","ENG":"However, the results were disappointing. Enough to make us pity those who were willing to make the sacrifice.","TWN":"然而結果卻並不理想。對於甘願犧牲的那些人，我們感到非常痛心。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……방금, 뭐라고 했어요? 뭘 어떻게 했다고요?","JPN":"……今、なんと言いましたか？　何をどうしたって？","ENG":"...W-what did you just say? You did what?","TWN":"……剛才，你說什麼？你做了什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"주민들을 제물로 바쳤답니다.","JPN":"住民を生贄として捧げました。","ENG":"We used the residents as sacrifices.","TWN":"我們把居民當成祭物獻祭了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"생명이라는 것은 무척이나 귀중하거든요. 특히 레지나 님처럼 특별한 분은요.","JPN":"命というものはとても貴重ですから。特にレジーナ様のように特別な方の場合はもっと。","ENG":"Life is extremely valuable. Especially when it's someone as special as you, Miss Regina.","TWN":"因為生命非常寶貴。尤其是像蕾佳娜這樣特別的人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"666명, 레지나 님께서 연명할 수 있다면 정말 놀랄 만큼 적은 숫자죠.","JPN":"666名、レジーナ様の命を繋ぐことができるのなら、本当に驚くほど少ない数です。","ENG":"666 people. If it means that you get to keep living, it is a small price to pay.","TWN":"666個人，如果能讓蕾佳娜活下去，這麼點犧牲真是很划算。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말도 안 되는 소리……","JPN":"あり得ないわ……","ENG":"That is...","TWN":"你在胡說什麼……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말도 안 되는 소리 마세요. 그런, 그런 농담을……","JPN":"バカ言わないでください。そんな、そんな冗談を……","ENG":"That is absurd. What kind of sick joke is–","TWN":"別、別在開這種玩笑了……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"후훗, 오해 마세요. 물론 진담이랍니다.","JPN":"ふふっ、誤解はいけませんね。もちろん本当ですよ。","ENG":"Hah hah, we're not joking.","TWN":"呵呵，你別誤會，這些當然都是真的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님은 시시각각 쇠약해지고 계셨어요.","JPN":"レジーナ様は刻一刻と衰弱していました。","ENG":"You were getting weaker by the minute.","TWN":"蕾佳娜每時每刻都在衰弱下去。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"카운터면서 자신의 냉기도 아니고, 고작 물에 한 번 빠진 것 때문에 앓을 만큼.","JPN":"カウンターでありながら自分の冷気ではなく、たかが一回水に落ちたくらいで病気を患うほどに。","ENG":"Weak enough for a Counter with Frost abilities to become ill simply from being drenched in water.","TWN":"明明是制裁者，而且自身本來就能控制寒氣，可就因為一次落水而生病。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"세라펠은 요물. 마왕이 되기 전에는 그녀에게 홀려 접근한 자들의 생기를 갈취하며 연명해 왔답니다.","JPN":"セラフェルは奸悪な者。魔王になる前までは、彼女に魅了され近づいてきた者の生気を吸い取り、延命してきました。","ENG":"Serapel is a monster. Before she became a Demon Lord, she survived by alluring victims and extorting their vitality.","TWN":"塞拉費爾是妖怪。在成為魔王之前，她就靠著奪取被她迷惑而靠近之人的生機續命。"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그렇기에 봉인에 갇힌 채, 기나긴 시간 쌓인 허기를 감히……","JPN":"だからでしょう。封印されたまま、長い間満たせなかった空腹をあろうことか……","ENG":"Having been sealed away and enduring the hunger, she...","TWN":"她也因此才會被封印，在漫長的歲月裡忍受著饑餓……"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"감히…… 레지나 님을 통해 해소했죠.","JPN":"……レジーナ様によって解消したのです。","ENG":"She dared to satisfy her cravings through you.","TWN":"她竟敢……藉由蕾佳娜來解決饑餓。"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"안타깝게도 저희가 도착했을 무렵에는 이미 모든 일이 끝난 뒤였어요.","JPN":"残念ながら、我々が着いた頃にはもうすべてが終わった後でした。","ENG":"Unfortunately, by the time we arrived, everything was already done.","TWN":"遺憾的是，我們到的時候，一切都已經結束了。"},"stage":{"bg":"SS_STREGA_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래서 결국 정신을 잃고 쓰러지신 날, 생각했답니다.","JPN":"そうしてついに気を失い倒れられたあの日、こう思ったのです。","ENG":"So when you passed out that day, a thought occurred.","TWN":"所以，在你失去意識昏迷的那天，我們思考了一番。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희가 레지나 님을 보호하더라도, 북의 폭군과 같은 자가 손을 뻗는다면 완벽하게 지켜내진 못하리라고요.","JPN":"我々がレジーナ様を保護しても、北の暴君のような者が手を出したら完璧に守り切ることはできないと。","ENG":"Even if we could protect you, we wouldn't be able to completely shield you from someone like the Tyrant of the North.","TWN":"就算有我們保護蕾佳娜，一旦像北方暴君那樣的人出手，我們也無法完全保護你。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하지만 레지나 님께서 저희와 같은 존재가 된다면.","JPN":"ですが、レジーナ様が我々のような存在になるとしたら。","ENG":"However, if you were to become like us...","TWN":"但是如果蕾佳娜變成和我們一樣的存在。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이 몸</color>이 저희를 불러들였던 것처럼, 현상에 한없이 가까운 존재로 거듭나신다면.","JPN":"<color=#ffd34c>この身体</color>が我々を呼び寄せたように、限りなく現象に近い存在に生まれ変わるとしたら。","ENG":"Just like how <color=#ffd34c>this body</color> summoned us, and you become a being closer to the natural order...","TWN":"就像<color=#ffd34c>這副身軀</color>召喚我們那樣，如果你能成為無限接近自然法則的存在。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그 때는 설령 북의 폭군이 나선다 한들, 완전한 죽음은 피할 수 있을 거라고.","JPN":"その時はたとえ北の暴君が現れようとも、完全なる死は避けられると。","ENG":"So even if the Tyrant of the North approaches, you will be able to cheat death.","TWN":"到時候就算北方暴君出手，你也能避免完全死亡的命運。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"웃기지 말아요!","JPN":"ふざけないで！","ENG":"You are insane!","TWN":"別說笑了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"고작 그런 이유 때문에 그렇게 많은 주민들을 희생시켰다고요?","JPN":"たかがそんな理由で、数多くの住民を犠牲にしたのですか？","ENG":"You murdered all those people just for that?!","TWN":"因為這種荒唐的理由，就犧牲了那麼多居民？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 당신도 선은 넘지 않았잖아요……? 저런 얘기를 듣고도 아무렇지 않아요?","JPN":"リベット、あなたも超えてはいけない一線は守っていたはずでしょう……？　あんな話を聞いて、なんとも思わないのですか？","ENG":"Rivet, you didn't cross the line, did you...? Why are you not disturbed by this?","TWN":"里維，你也越線了吧……？聽了這些話，你的內心也毫無感覺嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아하하, 그렇지만 레지나. 나는 에델에게 고용된 입장인걸.","JPN":"あはは、でもレジーナ。アタシはエデルに雇われた身だからさ。","ENG":"Ahaha, but Regina... Edel's the one who hired me, remember?","TWN":"哈哈哈，但是蕾佳娜，我是艾瑟兒雇來的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"가끔 밥 얻어 먹는 유사 침식체 수백 명이랑 너 하나 중에 누굴 택해야 하냐고 묻는다면, 용병으로서는 후자 아닐까?","JPN":"たまにご飯をくれる数百の類似侵食体とアンタ、どっちを選ぶかって聞かれたら、傭兵としては後者じゃないかな？","ENG":"As a mercenary, if I had to choose between you and hundreds of pseudo-C.O.s who occasionally feed me, wouldn't I pick the former?","TWN":"如果有人問我在偶爾蹭飯吃的幾百個類侵蝕體和你之間選擇誰，身為傭兵的我當然會選擇後者不是嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"유사 침식체……","JPN":"類似侵食体……","ENG":"Pseudo-C.O.s...?","TWN":"類侵蝕體……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"부학회장님을 위해서라고 하니 모두들 선뜻 자원해 주셨어요.","JPN":"副学会長のためだと説明したら、みなさん快く志願してくださいました。","ENG":"When we said it was all for you, they didn't hesitate to volunteer.","TWN":"我們說是為了副學會長，大家都欣然答應了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"혹여 이럴 때를 대비해서 주민들을 돌봐 주셨는지 저희도 깜짝 놀랐답니다.","JPN":"もしかしてこの時に備えて住民の面倒を見ていらしたのかと、我々もびっくりしました。","ENG":"We were just as surprised as you are, and even thought that this was why you took care of them for all this time.","TWN":"我們也嚇了一跳，或許你就是為了防備這種情況出現才會照顧居民們吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니야……","JPN":"違う……","ENG":"No...","TWN":"不是的……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Pardon?","TWN":"什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니라고!!","JPN":"違うわ！！","ENG":"You are wrong!","TWN":"我說不是！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"나는…… 나는 그저 그 사람들을 돕고 싶었던 거야.","JPN":"私は……私はただ、あの人たちを助けてあげたかっただけ。","ENG":"I... I just wanted to help them.","TWN":"我……我就是想幫助人們。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이용할 생각 따위 없었어…… 그런 쓸모없는 의식 따위에……!","JPN":"利用するつもりなんてなかった……そんな無価値な儀式なんかのために……！","ENG":"I had no intention of using them... Certainly not for this pointless ritual...!","TWN":"我根本沒想過利用他們……也沒想過那種毫無意義的儀式……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"쓸모없다니요. 레지나 님도 참.","JPN":"無価値だなんて。レジーナ様ったら。","ENG":"\\"Pointless\\"? Please, Miss Regina.","TWN":"怎麼能說毫無意義呢，蕾佳娜也真是的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"의식은 실제로 절반의 성공을 거두었답니다.","JPN":"儀式は実際に半分は成功しました。","ENG":"The ritual was actually half-successful.","TWN":"儀式其實已經成功了一半。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"보세요. 그 증거로, 레지나 님은 살아 계시잖아요?","JPN":"見てください。その証拠として、レジーナ様は生きていますよ？","ENG":"Look. As proof, you are still alive.","TWN":"你看，證據就是蕾佳娜現在還活，不是嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};